host_operator_src="""

#include "conv_transposed_3d_asymmetric_input_square_kernel_custom_tiling.h"
#include "register/op_def_registry.h"
#include <vector>

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // conservative per-core share
static constexpr uint32_t ALIGN_ELEMS = 2048;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b)  { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed3dAsymmetricInputSquareKernelCustomTilingData tiling;

    // Input shapes
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    if (x_shape->GetDimNum() != 5 || w_shape->GetDimNum() != 5) {
        return ge::GRAPH_FAILED;
    }
    int32_t N   = x_shape->GetDim(0);
    int32_t C_in= x_shape->GetDim(1);
    int32_t D   = x_shape->GetDim(2);
    int32_t H   = x_shape->GetDim(3);
    int32_t W   = x_shape->GetDim(4);

    int32_t C_out = w_shape->GetDim(1);  // weight shape: [C_in, C_out, kD, kH, kW]
    int32_t kD = w_shape->GetDim(2);
    int32_t kH = w_shape->GetDim(3);
    int32_t kW = w_shape->GetDim(4);

    // Read attributes
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const std::vector<int64_t>* stride_ptr   = attrs->GetAttrPointer<std::vector<int64_t>>(0);
    const std::vector<int64_t>* padding_ptr  = attrs->GetAttrPointer<std::vector<int64_t>>(1);
    const std::vector<int64_t>* output_padding_ptr = attrs->GetAttrPointer<std::vector<int64_t>>(2);
    int64_t groups = *attrs->GetAttrPointer<int64_t>(3);
    const std::vector<int64_t>* dilation_ptr = attrs->GetAttrPointer<std::vector<int64_t>>(4);

    std::vector<int64_t> stride = (stride_ptr) ? *stride_ptr : std::vector<int64_t>{1,1,1};
    std::vector<int64_t> padding = (padding_ptr) ? *padding_ptr : std::vector<int64_t>{0,0,0};
    std::vector<int64_t> output_padding = (output_padding_ptr) ? *output_padding_ptr : std::vector<int64_t>{0,0,0};
    std::vector<int64_t> dilation = (dilation_ptr) ? *dilation_ptr : std::vector<int64_t>{1,1,1};

    int32_t strideD = stride[0], strideH = stride[1], strideW = stride[2];
    int32_t padD = padding[0], padH = padding[1], padW = padding[2];
    int32_t outputPadD = output_padding[0], outputPadH = output_padding[1], outputPadW = output_padding[2];
    int32_t dilationD = dilation[0], dilationH = dilation[1], dilationW = dilation[2];

    // Compute output spatial sizes
    int32_t D_out = (D - 1) * strideD - 2 * padD + dilationD * (kD - 1) + outputPadD + 1;
    int32_t H_out = (H - 1) * strideH - 2 * padH + dilationH * (kH - 1) + outputPadH + 1;
    int32_t W_out = (W - 1) * strideW - 2 * padW + dilationW * (kW - 1) + outputPadW + 1;

    uint32_t totalLength = static_cast<uint32_t>(N) * C_out * D_out * H_out * W_out;

    // Tile size from UB budget: each output element we need to process one input tile? We'll use a simple scalar approach,
    // so UB budget is not heavily used. We'll set a conservative tile size.
    uint32_t maxTile = UB_BUDGET_BYTES / 4;  // each float 4 bytes, we store a portion of output
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    uint32_t tileLen = (totalLength < maxTile) ? totalLength : maxTile;
    tileLen = AlignDown(tileLen, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = totalLength;

    uint32_t blockDim = CeilDiv(totalLength, tileLen);
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;
    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_N(N);
    tiling.set_C_in(C_in);
    tiling.set_D(D);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_C_out(C_out);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_D_out(D_out);
    tiling.set_H_out(H_out);
    tiling.set_W_out(W_out);
    tiling.set_strideD(strideD);
    tiling.set_strideH(strideH);
    tiling.set_strideW(strideW);
    tiling.set_padD(padD);
    tiling.set_padH(padH);
    tiling.set_padW(padW);
    tiling.set_outputPadD(outputPadD);
    tiling.set_outputPadH(outputPadH);
    tiling.set_outputPadW(outputPadW);
    tiling.set_dilationD(dilationD);
    tiling.set_dilationH(dilationH);
    tiling.set_dilationW(dilationW);
    tiling.set_groups(static_cast<int32_t>(groups));

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

