    int32_t H   = x_shape->GetDim(3);
    int32_t W   = x_shape->GetDim(4);
    int32_t C_out = w_shape->GetDim(1);
    int32_t kD = w_shape->GetDim(2);
    int32_t kH = w_shape->GetDim(3);
    int32_t kW = w_shape->GetDim(4);

    // Read attributes
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    std::vector<int64_t> stride(3,1), padding(3,0), output_padding(3,0), dilation(3,1);
    int64_t groups = 1;
    if (attrs) {
