        if (auto ptr = attrs->GetAttrPointer<std::vector<int64_t>>(1)) padding = *ptr;
        if (auto ptr = attrs->GetAttrPointer<std::vector<int64_t>>(2)) output_padding = *ptr;
        if (auto ptr = attrs->GetAttrPointer<int64_t>(3)) groups = *ptr;
        if (auto ptr = attrs->GetAttrPointer<std::vector<int64_t>>(4)) dilation = *ptr;
    }

    int32_t D_out = (D - 1) * stride[0] - 2 * padding[0] + dilation[0] * (kD - 1) + output_padding[0] + 1;
    int32_t H_out = (H - 1) * stride[1] - 2 * padding[1] + dilation[1] * (kH - 1) + output_padding[1] + 1;
    int32_t W_out = (W - 1) * stride[2] - 2 * padding[2] + dilation[2] * (kW - 1) + output_padding[2] + 1;

    gert::Shape *y_shape = context->GetOutputShape(0);
    y_shape->SetDim(0, N);
    y_shape->SetDim(1, C_out);
    y_shape->SetDim(2, D_out);
    y_shape->SetDim(3, H_out);
    y_shape->SetDim(4, W_out);
    return GRAPH_SUCCESS;
}

